import{_ as a,o as t,c as s,ak as n}from"./chunks/framework.RPFtYYnm.js";const m=JSON.parse('{"title":"Fondamentaux","description":"","frontmatter":{},"headers":[],"relativePath":"fundamentals/index-fundamentals.md","filePath":"fundamentals/index-fundamentals.md"}'),i={name:"fundamentals/index-fundamentals.md"};function r(o,e,l,d,u,c){return t(),s("div",null,[...e[0]||(e[0]=[n(`<h1 id="fondamentaux" tabindex="-1">Fondamentaux <a class="header-anchor" href="#fondamentaux" aria-label="Permalink to “Fondamentaux”">​</a></h1><p>Les fondamentaux sont la base de tout parcours en cybersécurité offensive. Avant d&#39;attaquer des systèmes, comprendre comment ils fonctionnent est indispensable — un bon pentester est avant tout un bon technicien.</p><h2 id="pourquoi-les-fondamentaux" tabindex="-1">Pourquoi les fondamentaux ? <a class="header-anchor" href="#pourquoi-les-fondamentaux" aria-label="Permalink to “Pourquoi les fondamentaux ?”">​</a></h2><p>La cybersécurité offensive repose sur une compréhension profonde des systèmes, des protocoles et des architectures. Sans ces bases solides, il est impossible de comprendre pourquoi une attaque fonctionne, comment l&#39;adapter à un contexte différent ou comment expliquer l&#39;impact d&#39;une vulnérabilité à un client.</p><p>Les fondamentaux couverts dans cette section sont :</p><ul><li>Les systèmes d&#39;exploitation Linux et Windows</li><li>Les réseaux protocoles, ports, flux de données</li><li>La méthodologie structurer un engagement de bout en bout</li></ul><h2 id="contenu-de-la-section" tabindex="-1">Contenu de la Section <a class="header-anchor" href="#contenu-de-la-section" aria-label="Permalink to “Contenu de la Section”">​</a></h2><h3 id="methodologie-pentest" tabindex="-1">Méthodologie Pentest <a class="header-anchor" href="#methodologie-pentest" aria-label="Permalink to “Méthodologie Pentest”">​</a></h3><p>Cadre structuré pour mener un test d&#39;intrusion de la phase de pré-engagement jusqu&#39;au rapport final.</p><ul><li>Les 7 phases d&#39;un pentest</li><li>Cadres méthodologiques (PTES, OWASP, MITRE ATT&amp;CK)</li><li>Pre-engagement et règles d&#39;engagement</li><li>Reconnaissance, scanning, exploitation, post-exploitation</li><li>Rédaction de rapport professionnel</li><li>OPSEC et discrétion opérationnelle</li></ul><p><a href="/The-Hackers-237/fundamentals/pentest-methodology-fundamentals.html">Voir la page →</a></p><h3 id="linux-fundamentals" tabindex="-1">Linux Fundamentals <a class="header-anchor" href="#linux-fundamentals" aria-label="Permalink to “Linux Fundamentals”">​</a></h3><p>Maîtrise de la ligne de commande Linux indispensable car la majorité des outils offensifs et des serveurs cibles tournent sur Linux.</p><ul><li>Architecture et système de fichiers</li><li>Navigation, permissions et gestion des fichiers</li><li>Utilisateurs, groupes et sudo</li><li>Processus, services et cron jobs</li><li>Réseau et outils de diagnostic</li><li>Scripting Bash bases</li><li>Commandes essentielles pour le pentest</li></ul><p><a href="/The-Hackers-237/fundamentals/linux-fundamentals.html">Voir la page →</a></p><h3 id="windows-fundamentals" tabindex="-1">Windows Fundamentals <a class="header-anchor" href="#windows-fundamentals" aria-label="Permalink to “Windows Fundamentals”">​</a></h3><p>Compréhension de l&#39;architecture Windows et de ses mécanismes essentiel pour les environnements d&#39;entreprise et Active Directory.</p><ul><li>Architecture Windows et système de fichiers</li><li>Registre Windows structure et clés importantes</li><li>Permissions NTFS et gestion des utilisateurs</li><li>Processus, services et tâches planifiées</li><li>Authentification NTLM et Kerberos</li><li>PowerShell bases et techniques d&#39;exécution</li><li>Logs et Event IDs critiques</li></ul><p><a href="/The-Hackers-237/fundamentals/windows-fundamentals.html">Voir la page →</a></p><h3 id="networking" tabindex="-1">Networking <a class="header-anchor" href="#networking" aria-label="Permalink to “Networking”">​</a></h3><p>Protocoles réseau, adressage IP, ports et outils d&#39;analyse la base pour comprendre comment les systèmes communiquent et comment intercepter ou manipuler ce trafic.</p><ul><li>Modèles OSI et TCP/IP</li><li>TCP vs UDP Three-Way Handshake</li><li>Adressage IP, CIDR et subnetting</li><li>Ports et protocoles essentiels</li><li>DNS, DHCP, ARP, ICMP, HTTP</li><li>Outils réseau tcpdump, Wireshark, Nmap</li><li>Pivoting et tunneling SSH, ProxyChains, Chisel, Ligolo-ng</li><li>Attaques réseau ARP Spoofing, MITM, Responder</li></ul><p><a href="/The-Hackers-237/fundamentals/networking-fundamentals.html">Voir la page →</a></p><h2 id="ordre-d-apprentissage-recommande" tabindex="-1">Ordre d&#39;Apprentissage Recommandé <a class="header-anchor" href="#ordre-d-apprentissage-recommande" aria-label="Permalink to “Ordre d&#39;Apprentissage Recommandé”">​</a></h2><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span> 1. Networking        → Comprendre comment les systèmes communiquent</span></span>
<span class="line"><span> 2. Linux             → Maîtriser l&#39;environnement de travail offensif</span></span>
<span class="line"><span> 3. Windows           → Comprendre les cibles d&#39;entreprise</span></span>
<span class="line"><span> 4. Méthodologie      → Structurer les engagements</span></span></code></pre></div><h2 id="prerequis" tabindex="-1">Prérequis <a class="header-anchor" href="#prerequis" aria-label="Permalink to “Prérequis”">​</a></h2><p>Aucun prérequis strict n&#39;est nécessaire pour commencer cette section. Une familiarité basique avec l&#39;informatique (utiliser un terminal, naviguer dans des fichiers) est suffisante pour aborder les fondamentaux.</p><p>Pour aller plus loin après cette section :</p><table tabindex="0"><thead><tr><th>Section suivante</th><th>Lien</th></tr></thead><tbody><tr><td>Enumération réseau</td><td><a href="/The-Hackers-237/enumeration/">Voir →</a></td></tr><tr><td>Active Directory</td><td><a href="/The-Hackers-237/ad/">Voir →</a></td></tr><tr><td>Web Pentesting</td><td><a href="/The-Hackers-237/web/">Voir →</a></td></tr><tr><td>Cheatsheets</td><td><a href="/The-Hackers-237/cheatsheets/">Voir →</a></td></tr></tbody></table><div class="info custom-block"><p class="custom-block-title">Conseil</p><p>Ne pas chercher à tout mémoriser comprendre les concepts et savoir où trouver l&#39;information rapidement est bien plus efficace. Ces pages sont conçues pour être consultées pendant un engagement, pas uniquement pour l&#39;apprentissage.</p></div><h2 id="ressources-complementaires" tabindex="-1">Ressources Complémentaires <a class="header-anchor" href="#ressources-complementaires" aria-label="Permalink to “Ressources Complémentaires”">​</a></h2><ul><li><a href="https://overthewire.org/wargames/bandit/" target="_blank" rel="noreferrer">OverTheWire Bandit</a> Linux en pratique</li><li><a href="https://tryhackme.com/path/outline/presecurity" target="_blank" rel="noreferrer">TryHackMe Pre-Security</a> Fondamentaux interactifs</li><li><a href="https://academy.hackthebox.com/" target="_blank" rel="noreferrer">HackTheBox Academy Fundamentals</a> Cours structurés</li><li><a href="https://linuxcommand.org/tlcl.php" target="_blank" rel="noreferrer">The Linux Command Line William Shotts</a> Référence Linux gratuite</li><li><a href="https://www.professormesser.com/" target="_blank" rel="noreferrer">Professor Messer CompTIA Network+</a> Réseau complet</li></ul><div class="page-footer"><p><span><img src="https://img.shields.io/github/last-commit/Hackthus/The-Hackers-237?label=Last%20updated&amp;style=flat-square&amp;color=gray" alt="Last updated"></span></p><p><span><a href="https://github.com/Hackthus/The-Hackers-237/edit/main/docs/fundamentals/index.md" target="_blank" rel="noreferrer"><img src="https://img.shields.io/badge/%E2%9C%8F%EF%B8%8F%20Edit%20this%20page-GitHub-black?style=flat-square&amp;logo=github" alt="Edit this page on GitHub"></a></span></p></div>`,33)])])}const h=a(i,[["render",r]]);export{m as __pageData,h as default};
